const TZ = $('Encoding ( / for %2F )').first().json.body.timezone;
const LOCALE_ES = 'es-MX';

// Helpers de formato en zona horaria
const fmtDayKey = new Intl.DateTimeFormat('en-CA', { timeZone: TZ, year: 'numeric', month: '2-digit', day: '2-digit' }); // YYYY-MM-DD
const fmtWeekday = new Intl.DateTimeFormat('es-ES', { timeZone: TZ, weekday: 'long' });
const fmtHM = new Intl.DateTimeFormat(LOCALE_ES, { timeZone: TZ, hour: '2-digit', minute: '2-digit', hour12: false });

const capitalize = (s) => s ? s.charAt(0).toUpperCase() + s.slice(1) : s;

// 1) Recolectar el/los JSON de entrada y normalizar
const all = $input.all().map(i => i.json);
let records = [];
for (const j of all) {
  if (Array.isArray(j)) records.push(...j);
  else records.push(j);
}

// 2) Tomar la primera duraciÃ³n disponible y sus slots
let durationMs = null;
let availabilities = [];

for (const rec of records) {
  const byDuration = rec?.linkAvailability?.linkAvailabilityByDuration || {};
  const keys = Object.keys(byDuration);
  if (!keys.length) continue;

  const k = keys[0];
  const block = byDuration[k];
  const d = Number(k) || Number(block?.meetingDurationMillis);
  if (!isNaN(d) && block?.availabilities?.length) {
    durationMs = d;
    availabilities = block.availabilities;
    break;
  }
}

if (durationMs == null) {
  return [{
    json: {
      "DuraciÃ³n de la reuniÃ³n": "",
      "Dias y horarios disponibles": []
    }
  }];
}

// 3) Agrupar por dÃ­a local y formatear horarios
const byDay = new Map();

for (const slot of availabilities) {
  const startMs = Number(slot.startMillisUtc);
  if (isNaN(startMs)) continue;

  const d = new Date(startMs);
  const dayKey = fmtDayKey.format(d);               // 'YYYY-MM-DD'
  const weekday = capitalize(fmtWeekday.format(d)); // 'Martes', 'MiÃ©rcoles', etc.
  const time = fmtHM.format(d).replace(/\u202f|\u00a0/g, ''); // 'HH:MM' sin espacios duros

  if (!byDay.has(dayKey)) {
    byDay.set(dayKey, { weekday, times: new Set() });
  }
  byDay.get(dayKey).times.add(time);
}

// 4) Ordenar dÃ­as y armar el arreglo solicitado
const daysSorted = Array.from(byDay.entries()).sort((a, b) => a[0].localeCompare(b[0]));
const diasYHorarios = daysSorted.map(([dayKey, info]) => {
  const times = Array.from(info.times).sort((a, b) => a.localeCompare(b));
  return {
    "DÃ­a": `${info.weekday} ${dayKey}`,
    "Horarios": times.join(', ')
  };
});

// 5) Construir el JSON final con las claves exactas que pediste
const minutes = durationMs / 60000;
const output = {
  "Duracion de la reunion": `${durationMs} milissegundos (${minutes.toFixed(1)} minutos)`,
  "Dias y horarios disponibles": diasYHorarios
};

// 6) Devolver un Ãºnico item con ese JSON
return [{ json: output }];

